import './App.css';
import React from 'react';
import { v4 as uuid } from 'uuid';
import cookie from 'react-cookies';
import { Button, Tooltip } from '@material-ui/core';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

class TodoList extends React.Component {
	constructor(props) {
		super(props);
		this.state = JSON.parse(this.readCookie('todoapp')) || {
			input: '', todos: []
		};
		this.addTodo = this.addTodo.bind(this);
		this.handleInput = this.handleInput.bind(this);
		this.removeTodo = this.removeTodo.bind(this);
	}

	componentDidMount() { this.todoInput.focus(); }
	componentDidUpdate() { this.saveCookie('todoapp', JSON.stringify(this.state)); }
	readCookie(name) { // Starts
		let data = cookie.load(name);
		if (data === undefined) return null;
		else return JSON.stringify(data);
	} // Ends

	saveCookie(name, value) { // Starts
		const expires = new Date();
		expires.setDate(Date.now() + 1000 * 60 * 60 * 24 * 14);
		cookie.save( name, value, { path: '/', expires, secure: true, });
	} // Ends

	addTodo(){  // Starts
		if (this.state.input === '') {
			this.showToast("⚠️ Task Cannot Be Empty!");
		} else {
			const newTodo = { value: this.state.input, id: uuid() };
			this.setState(state => ({ todos: [ ...state.todos, newTodo], input: '' }));
		}
	} // Ends

	handleInput(evt){ // Starts
		if (evt.nativeEvent.key === "Enter"){ this.addTodo(); }
		else { this.setState({ input: evt.target.value }); }
	} // Ends

	removeTodo(id){ // Starts
		this.setState(state => {
			return {
				todos: state.todos.map(todo => {
					if (todo.id !== id){ return todo; }
					else { return { ...todo, deleted: true } }
				})
			};
		});

		setTimeout(() => {
			this.setState(state => { return { todos: state.todos.filter(t => t.id !== id) }});
		}, 1000);
	} // Ends

	showToast(text) { toast.dark(text, {
		position: "bottom-right", autoClose: 5000,
		hideProgressBar: false, closeOnClick: true,
		pauseOnHover: true, draggable: false, progress: undefined, });
	}

	render() { // Starts
		return (
			<div className="todo-list">
				<h1>Todo List</h1>

				{ this.state.todos.map(t =>
					<Todo key={t.id} {...t} onClick={()=>this.removeTodo(t.id)}/>)
				}

				<div className="controls">
					<input type="text"
						value={this.state.input}
						onChange={this.handleInput}
						onKeyDown={this.handleInput}
						ref={(input) => { this.todoInput = input; }} />
					<Button onClick={this.addTodo} color="primary">Add</Button>
				</div>
				<ToastContainer/>
			</div>
		)
	} // Ends

}

const Todo = ({value, onClick, deleted}) => (
	<div className={`todo ${deleted? 'deleted' : ''}`}>
		<Button variant="contained" onClick={onClick} color="secondary">
			<i className="far fa-trash-alt"></i>
		</Button>
		<Tooltip title={value} arrow>
			<div className="todoText">{value}</div>
		</Tooltip>
	</div>
);

export default TodoList;